import{_ as i,c as a,o as e,ak as t}from"./chunks/framework.CYxz2ou1.js";const o="/zimg/1.%E6%80%BB%E7%BB%93-1775385419652.png",_=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"NanoMind/C-工作/3-2025面试/1.总结.md","filePath":"NanoMind/C-工作/3-2025面试/1.总结.md","lastUpdated":1777709221000}'),r={name:"NanoMind/C-工作/3-2025面试/1.总结.md"};function n(s,l,p,d,h,u){return e(),a("div",null,[...l[0]||(l[0]=[t('<h2 id="自我介绍" tabindex="-1">自我介绍 <a class="header-anchor" href="#自我介绍" aria-label="Permalink to &quot;自我介绍&quot;">​</a></h2><p>我叫 XX，本硕毕业于重庆大学，目前毕业四年。毕业后我在猿辅导的工具应用部做服务端研发工程师，我在猿辅导 4 年时间呆过两个业务组。第一个是小猿口算业务组，这个组的产品是一个给用户提供作业拍照检查为核心能力的 APP，目前日活 900W。第二个项目组是目前所在的小猿学练机项目组，我们自研了一个安卓平板设备，然后把这个平板作为产品卖给用户，然后我们在设备上开发跟教育、学习相关的 APP，我们就是做相关业务的 Server 部分。可以看到我这四年其实做的主要都是 C 端的业务，我四年间的工作内容主要可以总结为两个部分，一是业务需求，我这边主 R 过大概二三十个中型到大型规模的业务，主要负责需求的前期评审、方案设计、方案对齐、需求研发、研发过程中的进度与风险管理、上线以及后续的数据运营等。另一部分工作则是技术需求相关，我们平时会有各种活动（比如 618 双 11），因此需要做活动的稳定性保障，同时也会做系统日常风险的清理，且会定期进行压测发现系统的问题与隐患，并针对性进行服务治理工作，进而保障系统的稳定性与可用性。这就是我这边的基本情况了。</p><h2 id="面试流程" tabindex="-1">面试流程 <a class="header-anchor" href="#面试流程" aria-label="Permalink to &quot;面试流程&quot;">​</a></h2><p>基本都是 2-3 轮技术，最后一轮 HR 面。</p><h2 id="面试问题" tabindex="-1">面试问题 <a class="header-anchor" href="#面试问题" aria-label="Permalink to &quot;面试问题&quot;">​</a></h2><p>比例：</p><ul><li><strong>项目问题：50%</strong></li><li><strong>八股文：30%</strong></li><li><strong>写题：20%</strong></li></ul><p><strong>记录下问的次数大于等于 2 次的问题</strong>：</p><ul><li>为什么离职。</li><li>近两年的绩效（几乎 80%的面试都问了，非常重要）。</li><li>是否有其他 offer，如何选择对比。</li><li>在这一家公司收获最大的地方、成长最大的地方。</li><li>映像最深刻的事情或者问题，后面如何处理或者解决的。</li><li>RocketMQ 与 Kafka 的区别。</li><li>Kafka 为什么这么快。</li><li>JVM 内存区域与垃圾收集算法。</li><li>写一个双重校验锁的单例，解释下为什么需要用 synchronized 和 volatile，分别影响什么。</li><li>分布式事务与如何保证数据一致性。</li><li>系统监控相关，需要设计哪些监控指标。</li><li>消息堆积如何处理。</li><li>如何保证消息不丢失。</li><li>Redis 的持久化机制。</li><li>MySQL 锁机制相关。</li><li>MySQL 事务相关。</li><li>MySQL 索引相关。</li><li>与领导力与沟通相关的问题，问的很多。</li></ul><p><strong>场景题：</strong></p><ul><li>5000 人的直播间实现同时抢 50 个红包的功能，如何实现系统。</li><li>快手用户一个人最多可以关注 1W 人，但是可以被无限制人数关注，如何实现拉取关注用户发的视频列表的功能。</li><li>设计一个 RPC 框架需要考虑什么。</li><li>如果你接手一个新系统，准备如何改进。</li><li>针对不同的公司或者岗位可能需要准备不同的场景题。</li></ul><p><strong>算法题：</strong></p><ul><li>大部分都是力扣中等，刷一下 Hot150 +剑指 offer 就够了。</li><li>遇到的题目：合并二叉树、合并区间、指定精度计算平方根、写一个 equals 方法、链表相加、反转指定范围的链表、删除链表中的重复元素 II、斜 45 度打印矩阵、有序矩阵的数据查找、复原 IP 地址、版本号比较、每日温度、字符串表达式的解析（没写出来）。</li><li>有两次面试写了业务代码。一个是 Shoppe 的写了一个直播间人数变化统计并进行告警的业务、一个是淘天写了一个实现会员注册与转账的业务。百度面试写了一个 SQL join，直接回答不会，然后换成写算法题。</li><li>本次考的题目都在 CodeTop 的前 200 个，刷一刷就够了。</li></ul><p>其他：</p><ul><li>网络相关一点没问，操作系统的就一个面试官问了比较多。</li></ul><h2 id="项目总结" tabindex="-1">项目总结 <a class="header-anchor" href="#项目总结" aria-label="Permalink to &quot;项目总结&quot;">​</a></h2><p>项目非常重要。一般都会<strong>问自己觉得最 🐂、映像最深刻的项目</strong>。一个好的项目可以吹的东西很多，所以要提前准备项目。</p><p>这次的简历写了 7 个项目，其实整体下来，问的最多的就重构的项目，顺带问了题目渲染项目和维修相关项目。口算的项目也只问了第一个。项目应该不需要太多，可以考虑下项目之间的关联性。比如我的重构项目，主要提到四件事：基于 DDD 进行领域建模、进行系统重构的代码实现、老系统的逻辑与数据的迁移、新系统核心接口的压测与服务治理。这里【新系统核心接口的压测与服务治理】又可以引申到题目渲染这个项目上来，就串起来了。</p><p>准备项目的方式：</p><ul><li>看看涉及哪些技术点，可以适当的构造一些场景。</li><li>一定要想清楚为什么要做这个项目或者需求，原因和动机往往更重要，不然都是白搭。</li><li>想清楚技术选型的原因，比如为什么用本地消息表+MQ 实现数据一致性，根据业务场景、团队内部的现状、公司的技术栈等来决定技术选型。适用更重要。</li><li>对于系统架构，考虑情况如果依赖的中间件、数据库、上下游出问题之后，应该怎么应对。比如依赖了 Redis 或者 MQ，那这俩挂了怎么办，是直接报错？还是走降级的思路先记录下来后面再补偿等。</li><li>思考一下当前系统还有什么可以提升的点，比如有哪些优化方向，系统流量番十倍还需要做什么，如果重新设计会怎么办等等。</li><li>画一下系统的架构图，比如单个服务的、整个业务的、整个系统的，有的面试官会让画一下架构图。</li><li>让 DeepSeak 看看可能会问哪些问题，提前准备。</li><li>面试官喜欢关注：技术选型、系统架构、方案设计、沟通对齐软实力、风险把控、成本预估等。</li></ul><h2 id="算法总结" tabindex="-1">算法总结 <a class="header-anchor" href="#算法总结" aria-label="Permalink to &quot;算法总结&quot;">​</a></h2><p>不需要刷特别多题目。目前自己题库的已经足够。<strong>注意一定要按照 CodeTop 里面的考查频率刷，非常有用</strong>！建议按照其顺序依次刷，并按照频次单独整理一个文档，随时复习。</p><h2 id="投递记录" tabindex="-1">投递记录 <a class="header-anchor" href="#投递记录" aria-label="Permalink to &quot;投递记录&quot;">​</a></h2><p><img src="'+o+'" alt=""></p>',24)])])}const f=i(r,[["render",n]]);export{_ as __pageData,f as default};
